import csv
from collections import defaultdict


def run_pipeline(input_file, output_file):
    # Data structure: department -> {'total_salary': float, 'count': int}
    stats = defaultdict(lambda: {"total_salary": 0.0, "count": 0})

    try:
        with open(input_file, mode="r", newline="") as csvfile:
            reader = csv.DictReader(csvfile)
            for row in reader:
                if row["status"].strip().lower() == "active":
                    dept = row["department"].strip()
                    try:
                        salary = float(row["salary"])
                        stats[dept]["total_salary"] += salary
                        stats[dept]["count"] += 1
                    except ValueError:
                        continue

        # Prepare results
        results = []
        for dept, data in stats.items():
            avg_salary = round(data["total_salary"] / data["count"], 2)
            results.append(
                {"department": dept, "avg_salary": avg_salary, "count": data["count"]}
            )

        # Sort by department name
        results.sort(key=lambda x: x["department"])

        # Write to output
        with open(output_file, mode="w", newline="") as csvfile:
            fieldnames = ["department", "avg_salary", "count"]
            writer = csv.DictWriter(csvfile, fieldnames=fieldnames)
            writer.writeheader()
            writer.writerows(results)

    except FileNotFoundError:
        print(f"Error: {input_file} not found.")
    except Exception as e:
        print(f"An error occurred: {e}")


if __name__ == "__main__":
    run_pipeline("input.csv", "output.csv")
